```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        return true;
    }

    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn.has_value()) {
        return false;
    }

    // Perform soft delete by updating is_deleted and deleted_at for each ID
    // Using a transaction to ensure atomicity of the batch operation
    for (int id : ids) {
        auto result = conn.and_then([id](auto& db) {
            return db.execute(
                update<Document>()
                    .set("is_deleted"_c = 1, "deleted_at"_c = DateTime::now())
                    .where("doc_id"_c == id)
            );
        });

        if (!result.has_value()) {
            return false;
        }
    }

    return true;
}

}  // namespace soft_delete_records
```

