      if (update_result.rows_affected() == 0) {
        // Insufficient funds - rollback
        sqlgen::sqlite::connect("test_db.sqlite")
          .and_then(execute("ROLLBACK"));
        return decltype(result)::error("Insufficient funds or account not found");
