      // Continue with adding to receiver
      return sqlgen::sqlite::connect("test_db.sqlite")
        .and_then(execute(
          "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
          amount, to_account_id));
    })
    .and_then(execute("COMMIT"));

  // If any step failed, attempt rollback
  if (!result.has_value()) {
    sqlgen::sqlite::connect("test_db.sqlite")
      .and_then(execute("ROLLBACK"));
    return false;
  }

  return true;
