template <class T>
std::string to_sql(const T& _t) noexcept {
  if constexpr (std::is_same_v<std::remove_cvref_t<T>, dynamic::Statement>) {
    return to_sql_impl(_t);
  } else {
    return to_sql_impl(transpilation::to_sql(_t));
  }
}

template <class... ColTypes>
auto order_by(const ColTypes&...) {
  return OrderBy<ColTypes...>{};
};

template <class ConditionType>
inline auto where(const ConditionType& _cond) {
  return Where<std::remove_cvref_t<ConditionType>>{.condition = _cond};
};

template <rfl::internal::StringLiteral _alias, class QueryType,
          class ConditionType>
auto inner_join(const QueryType& _query, const ConditionType& _on) {
  return join<_alias, transpilation::JoinType::inner_join>(_query, _on);
}

