#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;

  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  db.run(CreateTable<User>{});
  db.run(CreateTable<Friendship>{});

  // Clear existing data to ensure clean state
  db.run(Delete<User>{});
  db.run(Delete<Friendship>{});

  // Insert users
  for (const auto& user : users) {
    db.run(Insert(user));
  }

  // Insert friendships
  for (const auto& friendship : friendships) {
    db.run(Insert(friendship));
  }

  // Query for friend connections
  // This query joins Friendship with User table twice to get both usernames
  std::vector<FriendConnection> result;

  // Build query using sqlgen API
  // SELECT u1.username, u2.username
  // FROM Friendship f
  // INNER JOIN User u1 ON f.user1_id = u1.user_id
  // INNER JOIN User u2 ON f.user2_id = u2.user_id

  auto friendships_data = db.run(Select<Friendship>{});
  auto users_data = db.run(Select<User>{});

  // Create a map for quick user lookup
  std::unordered_map<int, std::string> user_map;
  for (const auto& user : users_data) {
    user_map[user.user_id.value] = user.username;
  }

  // Build friend connections
  for (const auto& friendship : friendships_data) {
    auto it1 = user_map.find(friendship.user1_id);
    auto it2 = user_map.find(friendship.user2_id);

    if (it1 != user_map.end() && it2 != user_map.end()) {
      result.push_back(FriendConnection{
        .user1_name = it1->second,
        .user2_name = it2->second
      });
    }
  }

  return result;
}

}  // namespace analyze_social_network

