      COS(discount_rate) as cos_discount,
      TAN(discount_rate) as tan_discount,
      SQRT(quantity) as sqrt_quantity
    FROM Product
  )";

  // Read results using the query
  auto results = read<std::vector<MathAnalysis>>(conn, query);

  if (!results) {
    return {};
  }

  return results.value();
}

