 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto db = sqlgen::sqlite::Connection("test_db.sqlite");

  // Build and execute the join query
  // Join Order with Customer on customer_id, then with Payment on order_id
  // Select order_id, customer name, and payment amount
  // Order by amount in descending order
  auto results = db.execute(
    Select<Order, Customer, Payment>{}
      .join<Customer>(where("Order.customer_id"_f == "Customer.customer_id"_f))
      .join<Payment>(where("Order.order_id"_f == "Payment.order_id"_f))
      .project_to<Consolidated>(
        "Order.order_id"_f,
        "Customer.name"_f,
        "Payment.amount"_f
      )
      .order_by("Payment.amount"_f, OrderBy::Desc)
  );

  return results;
}

}  // namespace join_orders_customers_payments
