#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to database, create tables, and insert data
  auto conn_result = sqlgen::sqlite::connect()
    .and_then(create_table<Department> | if_not_exists)
    .and_then(create_table<Employee> | if_not_exists)
    .and_then(insert(depts))
    .and_then(insert(emps));

  if (!conn_result) {
    return analysis;
  }

  // INNER JOIN: Get employees with assigned departments
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Department d INNER JOIN Employee e ON d.department_id = e.department_id
  {
    auto results = conn_result.and_then([](auto conn) {
      return conn.template read<std::vector<JoinResult>>(
        [](auto d, auto e) {
          return select(d->department_name, e->first_name, e->last_name, e->salary)
            .from(d)
            .join(e).on(d->department_id == e->department_id);
        }
      );
    });

    if (results) {
      analysis.inner_join_results = *results;
    }
  }

  // LEFT JOIN: All employees (even without departments)
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Employee e LEFT JOIN Department d ON e.department_id = d.department_id
  {
    auto results = conn_result.and_then([](auto conn) {
      return conn.template read<std::vector<JoinResult>>(
        [](auto e, auto d) {
          return select(d->department_name, e->first_name, e->last_name, e->salary)
            .from(e)
            .left_join(d).on(e->department_id == d->department_id);
        }
      );
    });

    if (results) {
      analysis.left_join_results = *results;
    }
  }

  // RIGHT JOIN: All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so we use LEFT JOIN with reversed order
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Department d LEFT JOIN Employee e ON d.department_id = e.department_id
  {
    auto results = conn_result.and_then([](auto conn) {
      return conn.template read<std::vector<JoinResult>>(
        [](auto d, auto e) {
          return select(d->department_name, e->first_name, e->last_name, e->salary)
            .from(d)
            .left_join(e).on(d->department_id == e->department_id);
        }
      );
    });

    if (results) {
      analysis.right_join_results = *results;
    }
  }

  // FULL JOIN: All employees and departments
  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it
  // by combining LEFT and RIGHT join results and removing duplicates
  analysis.full_join_results = analysis.left_join_results;

  // Add rows from right join that aren't in left join
  for (const auto& right_row : analysis.right_join_results) {
    bool found = false;
    for (const auto& left_row : analysis.left_join_results) {
      // Check if the row exists in left join (matching non-null values)
      if (left_row.department_name == right_row.department_name &&
          left_row.first_name == right_row.first_name &&
          left_row.last_name == right_row.last_name &&
          left_row.salary == right_row.salary) {
        found = true;
        break;
      }
    }
    if (!found) {
      analysis.full_join_results.push_back(right_row);
    }
  }

  return analysis;
}

}  // namespace analyze_department_employees
