```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database and execute the query
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([limit_count](auto&& conn) {
      // Execute raw SQL query with JOIN, aggregation, GROUP BY, ORDER BY and LIMIT
      return sqlgen::read<std::vector<TopProduct>>(
        conn,
        R"(
          SELECT 
            p.product_id,
            p.product_name,
            p.category,
            SUM(p.price * s.quantity) as total_sales
          FROM Product p
          INNER JOIN Sales s ON p.product_id = s.product_id
          GROUP BY p.product_id, p.product_name, p.category
          ORDER BY total_sales DESC
          LIMIT ?
        )",
        limit_count
      );
    });

  // Return the result or an empty vector if the query fails
  return result.value_or(std::vector<TopProduct>{});
}

}  // namespace get_top_products
```

