```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::Connection{"test_db.sqlite"};

  // SQL query to extract weekday and aggregate totals
  // strftime('%w', sale_time) returns day of week (0=Sunday, 6=Saturday)
  const auto query = 
    "SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday, "
    "SUM(quantity) as total_quantity "
    "FROM Sales "
    "GROUP BY weekday "
    "ORDER BY weekday";

  // Execute query and return results
  return conn.read<WeekdayStats>(query);
}

}  // namespace weekday_sales_analysis
```

This implementation:

1. **Connects to the database**: Creates a connection to "test_db.sqlite" using `sqlgen::sqlite::Connection`

2. **Extracts weekday from sale_time**: Uses SQLite's `strftime('%w', sale_time)` function which returns the day of week as a number (0-6, where 0 is Sunday)

3. **Aggregates totals per weekday**: Uses `SUM(quantity)` grouped by the extracted weekday value

4. **Returns weekday metrics**: The query results are mapped to `WeekdayStats` structs and returned as a vector

The query groups all sales by weekday and calculates the total quantity sold for each day of the week, ordered from Sunday (0) to Saturday (6).

