namespace group_by_with_aggregations {

TEST(sqlite, group_by_with_aggregations) {
  using namespace sqlgen;

  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<User>(conn);
  drop<Post>(conn);
  create_table<User>(conn);
  create_table<Post>(conn);

  std::vector<User> users{{1, "Alice"}, {2, "Bob"}};
  std::vector<Post> posts{{1, 1, "hello"}, {2, 1, "world!!!"}, {3, 2, "x"}};
  insert(conn, users);
  insert(conn, posts);

  auto stats = group_by_with_aggregations();
  ASSERT_GE(stats.size(), 2);
}

}  // namespace group_by_with_aggregations

