auto max(const T& _t) {
  using Type =
      typename transpilation::ToTranspilationType<std::remove_cvref_t<T>>::Type;
  return transpilation::Aggregation<transpilation::AggregationOp::max, Type>{
      .val = transpilation::to_transpilation_type(_t)};
}

