  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlite::open("test_db.sqlite");

  // Get table references
  auto users = db.get_table<User>("User");
  auto posts = db.get_table<Post>("Post");

  // Build and execute the query with JOIN, GROUP BY, and aggregations
  // SELECT u.user_id, u.name, COUNT(p.post_id), AVG(LENGTH(p.content))
  // FROM User u
  // LEFT JOIN Post p ON u.user_id = p.user_id
  // GROUP BY u.user_id, u.name
  auto results = db.query()
    .select(
      users.user_id,
      users.name,
      count(posts.post_id),
      avg(length(posts.content))
    )
    .from(users)
    .left_join(posts).on(users.user_id == posts.user_id)
    .group_by(users.user_id, users.name)
    .as<Stats>();

  return results;
}

}  // namespace group_by_with_aggregations

