```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    return create_table_as<Target>(
        from<Source>().where("value"_c > 100)
    );
}

}  // namespace create_table_as_select
```

This implementation:
1. Uses the `sqlgen` namespace and literals for column references
2. Constructs a `create_table_as<Target>` statement that creates the Target table
3. Selects from `Source` using `from<Source>()`
4. Filters records with `where("value"_c > 100)` to only include records where value is greater than 100
5. Returns the constructed query object

The `"value"_c` syntax is a sqlgen literal that references the `value` column, and the query will automatically map the matching fields from Source to Target (in this case, just the `value` field).

